is_pri = [False] * 1005
pri = []

is_pri[2] = True

def is_prime(n):
    if is_pri[n]:
        return True
    for i in pri:
        if n%i == 0:
            return False
    return True

for i in range(2,1001):
    if is_prime(i):
        pri.append(i)

input()

print(" ".join(map(str,[j for i,j in enumerate(map(int,input().split())) if i+1 not in pri])))
